+import AppKit
+import Foundation
+
+@MainActor
+final class AppController: ObservableObject {
+    @Published private(set) var status: AppStatus = .loading
+
+    func markReady() {
+        status = .ready
+    }
+
+    func showError(_ message: String) {
+        status = .error(message)
+    }
+
+    func quit() {
+        NSApp.terminate(nil)
+    }
+}

