+import AppKit
+
+final class AppDelegate: NSObject, NSApplicationDelegate {
+    func applicationDidFinishLaunching(_ notification: Notification) {
+        ProcessInfo.processInfo.disableAutomaticTermination("Ghost Pepper keeps a persistent menu bar presence.")
+    }
+
+    func applicationWillTerminate(_ notification: Notification) {
+        ProcessInfo.processInfo.enableAutomaticTermination("Ghost Pepper is shutting down.")
+    }
+}

